class Solution(object):
    def maxProfit(self, prices):
        if len(prices) < 2:
            return 0
        hold, sold, rest = -prices[0], 0, 0
        for price in prices[1:]:
            hold, sold, rest = max(hold, rest - price), max(sold, hold + price), max(rest, sold)
        return max(sold, rest)
